const app = { selectedId: null, current: null, interviews: [], resumes: [], research: [], researchCandidates: [], resumeId: '', jdAnalysis: null, selectedAudio: null, selectedResumeFile: null, editingResumeId: null, editingResearchId: null, pendingResearchMeta: null, noteQuestions: [], activeTask: null };
const ACCESS_TOKEN_KEY = 'autumn-assistant-access-token';
function provenanceLabel(value) { return ({ auto_fetched_unverified: '自动读取 · 未人工确认', manual_check_required: '需人工打开 / 摘录', citation_verified: '搜索引用已核对' })[value] || '来源状态未知'; }
const renderResearchListWithProvenance = renderResearchList;
renderResearchList = () => { renderResearchListWithProvenance(); $$('#research-list .research-item').forEach((card, index) => { const badge = document.createElement('span'); badge.className = 'provenance-badge'; badge.textContent = provenanceLabel(app.research[index]?.provenance_status); card.querySelector('.status-badge')?.after(badge); }); };

async function api(url, options = {}) {
  const response = await fetch(url, { headers: { 'Content-Type': 'application/json', ...accessHeaders(), ...(options.headers || {}) }, ...options });
  const data = await response.json();
  if (response.status === 401) throw Error('需要访问口令。');
  if (!response.ok || !data.ok) { const error = Error(data.error || '请求没有完成。'); error.status = response.status; error.payload = data; throw error; }
  return data;
}
async function waitForTask(task, onUpdate = () => {}, allowRetry = true) {
  if (!task?.id) throw Error('服务没有返回有效任务。');
  renderTaskStatus(task);
  for (let attempt = 0; attempt < 120; attempt += 1) {
    const current = (await api(`/api/tasks/${task.id}`)).task;
    renderTaskStatus(current);
    onUpdate(current);
    if (current.status === 'succeeded') return current.result || {};
    if (['failed', 'timed_out', 'abandoned', 'cancelled'].includes(current.status)) {
      if (current.status === 'failed' && allowRetry && current.attempt < current.max_attempts && window.confirm(`任务第 ${current.attempt} 次执行失败：${current.error || '未知错误'}\n是否按原步骤重试？`)) {
        const retried = await api(`/api/tasks/${current.id}/retry`, { method: 'POST', body: '{}' });
        return waitForTask(retried.task, onUpdate, false);
      }
      const error = Error(current.error || (current.status === 'abandoned' ? '应用重启时任务中断，请重新提交。' : (current.status === 'cancelled' ? '任务已取消。' : '后台任务失败。')));
      error.task = current;
      throw error;
    }
    await new Promise(resolve => setTimeout(resolve, 750));
  }
  throw Error('任务等待超时，请稍后到任务状态中重试。');
}
function renderTaskStatus(task) {
  const root = $('#task-status');
  const label = $('#task-status-label');
  const cancel = $('#cancel-task');
  if (!root || !label || !cancel) return;
  if (!task) { root.hidden = true; app.activeTask = null; return; }
  const labels = { queued: '任务排队中', running: '后台执行中', cancel_requested: '正在取消', succeeded: '任务已完成', failed: '任务失败', timed_out: '任务超时', cancelled: '任务已取消', abandoned: '任务因重启中断' };
  root.hidden = false;
  root.className = `task-status ${task.status || ''}`;
  label.textContent = `${labels[task.status] || '后台任务'} · 第 ${task.attempt || 0} 次`;
  cancel.hidden = !['queued', 'running'].includes(task.status);
  cancel.disabled = task.status === 'cancel_requested';
  app.activeTask = task;
}
async function cancelActiveTask() {
  const task = app.activeTask;
  if (!task?.id || !['queued', 'running'].includes(task.status)) return;
  try {
    const data = await api(`/api/tasks/${task.id}/cancel`, { method: 'POST', body: '{}' });
    renderTaskStatus(data.task);
    toast(data.task.status === 'cancelled' ? '任务已取消。' : '已请求取消，当前网络调用可能仍在收尾。');
  } catch (error) { toast(error.message); }
}
function accessHeaders() { const token = sessionStorage.getItem(ACCESS_TOKEN_KEY); return token ? { 'X-App-Token': token } : {}; }
function toast(message) { const box = $('#toast'); box.textContent = message; box.hidden = false; clearTimeout(toast.timer); toast.timer = setTimeout(() => box.hidden = true, 5000); }
function busy(button, isBusy, label) { button.disabled = isBusy; button.textContent = isBusy ? label : button.dataset.label; }
function field(name) { return interviewForm.elements.namedItem(name); }
const SENSITIVE_PATTERNS = [
  ['手机号', /(?:\+?86[-\s]?)?1[3-9]\d{9}/],
  ['邮箱地址', /[\w.+-]+@[\w.-]+\.[A-Za-z]{2,}/],
  ['身份证号', /\b\d{17}[\dXx]\b/],
];
function updateSensitiveWarning() {
  const warning = $('#sensitive-warning');
  if (!warning) return;
  const material = ['job_description', 'resume_context', 'transcript', 'personal_notes']
    .map(name => field(name)?.value || '').join('\n');
  const labels = SENSITIVE_PATTERNS.filter(([, pattern]) => pattern.test(material)).map(([label]) => label);
  warning.hidden = !labels.length;
  warning.textContent = labels.length
    ? `可能包含敏感信息：检测到${labels.join('、')}。请发送前自行删减；此提示不代表完整脱敏。`
    : '';
}
function setView(viewId) { $$('.view').forEach(view => view.classList.toggle('active', view.id === viewId)); $$('.nav-button').forEach(button => button.classList.toggle('active', button.dataset.view === viewId)); const titles = { 'review-view': '面试复盘', 'research-view': '面经资料库', 'growth-view': '阶段成长报告', 'resume-view': '简历库' }; $('#page-title').textContent = viewId === 'review-view' && app.current ? `${app.current.company} · ${app.current.role}` : titles[viewId]; $('#top-eyebrow').textContent = viewId === 'review-view' ? 'INTERVIEW REVIEW WORKSPACE · V3' : 'AUTUMN PM COACH · V3'; }
function interviewPayload() { const data = Object.fromEntries(interviewFields.map(name => [name, field(name).value])); const resume = app.resumes.find(item => item.id === app.resumeId); return { ...data, outcome_source: data.outcome ? 'self_reported' : '', resume_id: app.resumeId, resume_name: resume?.name || app.current?.resume_name || '', jd_analysis: app.jdAnalysis, research_context: app.researchCandidates }; }

function renderInterviewList() { const list = $('#interview-list'); list.replaceChildren(); $('#interview-total').textContent = app.interviews.length; if (!app.interviews.length) { list.innerHTML = '<p class="empty-copy">还没有面试档案。</p>'; return; } app.interviews.forEach(item => { const button = document.createElement('button'); button.type = 'button'; button.className = `interview-item ${item.id === app.selectedId ? 'active' : ''}`; button.innerHTML = `<strong></strong><span></span>`; button.querySelector('strong').textContent = `${item.company} · ${item.role}`; button.querySelector('span').textContent = `${item.round_name || '面试'} · ${item.date || '未填写日期'}${item.has_review ? ' · 已复盘' : ''}`; button.onclick = () => loadInterview(item.id); list.append(button); }); }
function renderMetrics() { $('#metric-total').textContent = app.interviews.length; $('#metric-actions').textContent = app.interviews.reduce((sum, item) => sum + item.open_actions, 0); $('#metric-reviews').textContent = app.interviews.filter(item => item.has_review).length; const usable = app.research.filter(item => item.status === 'approved').length; $('#metric-research').textContent = usable; $('#research-nav-count').textContent = usable; }
async function refreshInterviews() { app.interviews = (await api('/api/interviews')).interviews; renderInterviewList(); renderMetrics(); }
async function refreshResumes() { app.resumes = (await api('/api/resumes')).resumes; const select = $('#resume-select'); const old = app.resumeId; select.replaceChildren(new Option('暂不关联简历', '')); app.resumes.forEach(item => select.add(new Option(`${item.name}${item.target_role ? ' · ' + item.target_role : ''}`, item.id))); select.value = old; renderResumeList(); }
async function refreshResearch() { const data = await api('/api/research'); app.research = data.research; $('#research-total').textContent = data.stats.total; $('#research-usable').textContent = data.stats.usable; $('#research-review').textContent = data.stats.needs_review; renderResearchList(); renderMetrics(); }

function resetInterview() { app.selectedId = null; app.current = null; app.resumeId = ''; app.jdAnalysis = null; app.researchCandidates = []; app.selectedAudio = null; app.noteQuestions = []; renderNoteQuestions([]); interviewFields.forEach(name => field(name).value = name === 'status' ? '待复盘' : ''); $('#resume-select').value = ''; $('#resume-preview').textContent = '选择一份简历；保存面试时会记录当时的内容快照。'; $('#jd-analysis').hidden = true; $('#jd-research-handoff').hidden = true; $('#audio-state').textContent = '尚未选择录音'; $('#consent-check').checked = false; $('#redact-company').checked = false; $('#delete-interview').hidden = true; $('#page-title').textContent = '新建一场面试复盘'; updateSensitiveWarning(); setSaveState('未保存'); setReviewState('等待资料'); renderReview(null); renderInterviewList(); setView('review-view'); }
