function renderSkillCard(skill) {
  const card = document.createElement('article');
  card.className = 'skill-score';
  card.innerHTML = '<div class="skill-score-head"><div><strong></strong><small></small></div><span></span></div><p class="evidence"></p><p class="skill-diagnosis-copy"></p><div class="evidence-profile"></div><details><summary>展开评分依据</summary><div class="dimension-list"></div><div class="skill-gap-list"></div><div class="practice-plan"></div></details>';
  card.querySelector('.skill-score-head strong').textContent = skill.skill_name || skill.skill_id || 'PM 能力';
  card.querySelector('.skill-score-head small').textContent = `${skill.confidence || '未知'} 置信度 · 覆盖 ${Math.round((skill.evidence_coverage || 0) * 100)}%`;
  card.querySelector('.skill-score-head > span').textContent = skill.score == null ? '未评分' : `${skill.score}/5`;
  card.querySelector('.evidence').textContent = `证据：${skill.evidence || '未提供'}`;
  card.querySelector('.skill-diagnosis-copy').textContent = skill.diagnosis || '暂无诊断。';
  const profileLabels = { specificity: '具体性', ownership: '个人归因', causality: '因果验证', result_quality: '结果质量', reflection: '复盘迁移', probe_resilience: '追问韧性' };
  card.querySelector('.evidence-profile').textContent = `证据剖面：${Object.entries(profileLabels).map(([key, label]) => `${label} ${skill.evidence_profile?.[key] ?? 0}/3`).join(' · ')}`;
  const dimensions = card.querySelector('.dimension-list');
  (skill.dimensions || []).forEach(dimension => {
    const row = document.createElement('div');
    row.className = 'dimension-row';
    row.innerHTML = '<div><strong></strong><span></span></div><p></p><small></small>';
    row.querySelector('strong').textContent = dimension.label || dimension.id;
    row.querySelector('span').textContent = dimension.score == null ? '未展示' : `${dimension.score}/5`;
    row.querySelector('p').textContent = `状态：${dimension.status || 'unknown'} · ${dimension.rationale || ''}`;
    row.querySelector('small').textContent = `证据：${dimension.evidence || '未提供'}`;
    dimensions.append(row);
  });
  const gaps = card.querySelector('.skill-gap-list');
  (skill.gaps || []).forEach(gap => {
    const item = document.createElement('p');
    item.textContent = `缺口 ${gap.severity || 'medium'}：${gap.impact || gap.gap_id} · 证据：${gap.evidence || '未提供'}`;
    gaps.append(item);
  });
  const plan = skill.practice_plan || {};
  if (plan.action || plan.prompt || plan.success_criteria?.length) {
    const practice = card.querySelector('.practice-plan');
    practice.innerHTML = '<strong>下一步训练</strong><p></p><ul></ul><small></small>';
    practice.querySelector('p').textContent = plan.prompt ? `${plan.action || '训练'}：${plan.prompt}` : (plan.action || skill.next_practice || '补充一轮练习');
    (plan.success_criteria || []).forEach(item => { const li = document.createElement('li'); li.textContent = item; practice.querySelector('ul').append(li); });
    practice.querySelector('small').textContent = plan.follow_up_question ? `下一条追问：${plan.follow_up_question}` : '';
  }
  return card;
}

function renderReview(review) {
  const root = $('#review-content'); root.replaceChildren(); root.hidden = !review; $('#review-empty').hidden = !!review; if (!review) return;
  root.append(renderScoreSummary(review));
  root.append(renderShortTermMemory(review));
  const summary = document.createElement('div'); summary.className = 'review-summary'; summary.textContent = review.summary || ''; root.append(summary);
  renderCoachItems(root, '表现亮点', review.strengths, 'why_it_worked'); renderCoachItems(root, '需要补强', review.gaps, 'improvement');
  if (review.skill_diagnosis?.length) { const section = reviewSection('PM 能力诊断'); const grid = document.createElement('div'); grid.className = 'skill-score-grid'; review.skill_diagnosis.forEach(skill => grid.append(renderSkillCard(skill))); section.append(grid); root.append(section); }
  if (review.questions?.length) { const section = reviewSection('逐题复盘'); const list = document.createElement('div'); list.className = 'question-list'; review.questions.forEach(question => { const card = document.createElement('article'); card.className = 'question-item'; card.innerHTML = '<div class="question-top"><strong></strong><span class="score"></span></div><p class="answer"></p><p class="evidence"></p><p class="assessment"></p><p class="question-meta"></p><p class="next"></p>'; card.querySelector('strong').textContent = question.question; card.querySelector('.score').textContent = `${question.score}/5`; card.querySelector('.answer').textContent = question.answer_summary || ''; card.querySelector('.evidence').textContent = `证据：${question.evidence || ''}`; card.querySelector('.assessment').textContent = question.assessment || ''; card.querySelector('.question-meta').textContent = `证据状态：${question.evidence_quality || 'unknown'}${question.skills?.length ? ` · 能力：${question.skills.join('、')}` : ''}`; card.querySelector('.next').textContent = `练习：${question.next_practice || ''}`; list.append(card); }); section.append(list); root.append(section); }
  if (review.action_plan?.length) { const section = reviewSection('下一步行动'); const list = document.createElement('div'); list.className = 'action-list'; review.action_plan.forEach(action => { const row = document.createElement('label'); row.className = `action-item ${action.done ? 'done' : ''}`; row.innerHTML = '<input type="checkbox" /><div><strong></strong><span></span></div><b></b>'; const checkbox = row.querySelector('input'); checkbox.checked = !!action.done; checkbox.onchange = () => toggleAction(action.id, checkbox.checked); row.querySelector('strong').textContent = action.action; row.querySelector('span').textContent = action.reason; row.querySelector('b').textContent = action.priority || '中'; list.append(row); }); section.append(list); root.append(section); }
  if (review.follow_up) { const section = reviewSection('后续建议'); const text = document.createElement('div'); text.className = 'follow-up'; text.textContent = review.follow_up; section.append(text); root.append(section); }
}

function enhanceActionItems(review) {
  $$('#review-content .action-item').forEach((row, index) => {
    const action = review.action_plan?.[index];
    if (!action) return;
    const content = row.querySelector('div');
    if (!content || content.querySelector('.action-verification')) return;
    const verification = document.createElement('div');
    verification.className = 'action-verification';
    const criteria = document.createElement('small');
    criteria.textContent = action.success_criteria?.length ? `验收标准：${action.success_criteria.join('；')}` : '验收标准：完成后补充下一场验证。';
    const nextValidation = document.createElement('small');
    nextValidation.textContent = action.next_validation ? `下一场验证：${action.next_validation}` : '下一场验证：尚未填写。';
    const select = document.createElement('select');
    select.innerHTML = '<option value="pending">待验收</option><option value="passed">已通过</option><option value="needs_retry">需重练</option>';
    select.value = action.acceptance_status || 'pending';
    const note = document.createElement('input');
    note.type = 'text'; note.maxLength = 800; note.placeholder = '验收备注（可选）'; note.value = action.acceptance_note || '';
    const sync = () => toggleAction(action.id, row.querySelector('input').checked, select.value, note.value);
    row.querySelector('input').onchange = sync;
    select.onchange = sync;
    note.onchange = sync;
    const progress = action.training_progress || {};
    const progressLabel = document.createElement('small');
    progressLabel.className = 'training-progress';
    progressLabel.textContent = `训练闭环：${progress.pre_test ? '前测' : '前测待做'} · ${progress.rewrite ? '重写' : '重写待做'} · ${progress.post_test ? '后测' : '后测待做'}${progress.attempt_count ? ` · ${progress.attempt_count} 次记录` : ''}`;
    const attempts = document.createElement('div');
    attempts.className = 'training-attempts';
    (action.attempts || []).slice(-3).forEach(attempt => {
      const item = document.createElement('small');
      item.textContent = `${({ pre_test: '前测', rewrite: '重写', post_test: '后测' })[attempt.phase] || attempt.phase}：${attempt.response}`;
      attempts.append(item);
    });
    const phase = document.createElement('select');
    phase.innerHTML = '<option value="pre_test">记录前测</option><option value="rewrite">记录重写</option><option value="post_test">记录后测</option>';
    const response = document.createElement('textarea');
    response.rows = 2; response.maxLength = 4000; response.placeholder = '填写本阶段的回答，再保存训练记录';
    const addAttempt = document.createElement('button');
    addAttempt.type = 'button'; addAttempt.className = 'secondary-button compact-button'; addAttempt.textContent = '保存训练记录';
    addAttempt.onclick = () => recordTrainingAttempt(action.id, phase.value, response.value, addAttempt);
    const completion = document.createElement('small');
    completion.textContent = action.completed_at ? `完成时间：${action.completed_at}` : '完成时间：尚未完成';
    verification.append(criteria, nextValidation, progressLabel, attempts, completion, select, note, phase, response, addAttempt);
    content.append(verification);
  });
}
const renderReviewWithActions = renderReview;
renderReview = review => { renderReviewWithActions(review); if (review) enhanceActionItems(review); };
async function toggleAction(id, done, acceptanceStatus = 'pending', acceptanceNote = '') { const action = app.current?.review?.action_plan?.find(item => item.id === id); if (acceptanceStatus === 'passed' && !action?.training_progress?.post_test) { toast('请先完成前测、重写和后测，再标记训练为已通过。'); renderReview(app.current.review); return; } try { app.current = (await api(`/api/interviews/${app.selectedId}/actions/${id}`, { method: 'PATCH', body: JSON.stringify({ done, acceptance_status: acceptanceStatus, acceptance_note: acceptanceNote }) })).interview; renderReview(app.current.review); await refreshInterviews(); } catch (error) { toast(error.message); } }
async function recordTrainingAttempt(actionId, phase, response, button) { if (!response.trim()) { toast('请先填写这一阶段的回答。'); return; } busy(button, true, '保存中...'); try { app.current = (await api(`/api/interviews/${app.selectedId}/actions/${actionId}/attempts`, { method: 'POST', body: JSON.stringify({ phase, response }) })).interview; renderReview(app.current.review); await refreshInterviews(); } catch (error) { toast(error.message); } finally { busy(button, false, ''); } }
async function deleteInterview() { if (!app.selectedId || !window.confirm('删除后会同时移除这场复盘及其长期记忆来源，确定继续吗？')) return; try { await api(`/api/interviews/${app.selectedId}`, { method: 'DELETE' }); toast('已删除这场记录，长期记忆会在下次读取时重新计算。'); resetInterview(); await refreshInterviews(); await refreshGrowthMemory(); } catch (error) { toast(error.message); } }
function renderJd() { const root = $('#jd-analysis'); root.replaceChildren(); if (!app.jdAnalysis) { root.hidden = true; return; } root.hidden = false; const title = document.createElement('strong'); title.textContent = app.jdAnalysis.role_title || '岗位画像'; root.append(title); [['职责', 'responsibilities'], ['要求', 'requirements'], ['关键词', 'keywords'], ['可能追问', 'interview_focus'], ['搜索主题', 'search_topics']].forEach(([label, key]) => { if (!app.jdAnalysis[key]?.length) return; const group = document.createElement('div'); group.innerHTML = '<span></span><ul></ul>'; group.querySelector('span').textContent = label; app.jdAnalysis[key].forEach(item => { const li = document.createElement('li'); li.textContent = item; group.querySelector('ul').append(li); }); root.append(group); }); }
function renderJdResearch(data) { const root = $('#jd-research-handoff'); if (!root) return; const candidates = data?.candidates || []; root.hidden = !candidates.length; if (!candidates.length) return; root.querySelector('strong').textContent = `已按 JD 自动发现 ${candidates.length} 条面经线索`; root.querySelector('span').textContent = 'Agent 已自动规划查询、读取公开页面并由后端收录；自动读取结果仍需来源确认后才可作为证据。'; }
async function autoSearchFromJd(raw, analysis) { const topic = [...(analysis.search_topics || []), ...(analysis.search_synonyms || []), ...(analysis.interview_focus || []), ...(analysis.keywords || [])].slice(0, 10).join(' '); const payload = { company: field('company').value, role: field('role').value || analysis.role_title || '产品经理', round_name: field('round_name').value, topic, job_description: raw, jd_analysis: analysis, platform: $('#discover-platform')?.value || 'all', async: true }; const accepted = await api('/api/research/agent', { method: 'POST', body: JSON.stringify(payload) }); const data = await waitForTask(accepted.task, task => { if (task.status === 'queued') renderSearchMeta({ platform_label: '后台排队中', result_count: 0 }); if (task.status === 'running') renderSearchMeta({ platform_label: 'Agent 调研中', result_count: 0 }); }); app.researchCandidates = data.persisted || data.collected || []; renderSearchMeta(data.search_meta); renderAgentTrace(data.trace, data.stop_reason, data.found_enough); renderJdResearch({ ...data, candidates: app.researchCandidates }); renderDiscovery(app.researchCandidates); await refreshResearch(); }
async function extractJd() { const raw = field('job_description').value.trim(); if (raw.length < 30) { toast('请先粘贴一段足够完整的 JD。'); return; } const button = $('#extract-jd'); busy(button, true, '正在解析并搜索...'); try { app.jdAnalysis = (await api('/api/extract-jd', { method: 'POST', body: JSON.stringify({ job_description: raw }) })).analysis; if (!field('role').value && app.jdAnalysis.role_title) field('role').value = app.jdAnalysis.role_title; renderJd(); setSaveState('JD 已解析'); try { await autoSearchFromJd(raw, app.jdAnalysis); toast('已按 JD 自动识别并收录面经候选；问题生成会引用这些线索。'); } catch (error) { renderJdResearch({ candidates: [] }); toast(`JD 已解析，但自动搜索未完成：${error.message}`); } } catch (error) { toast(error.message); } finally { busy(button, false, ''); } }
async function transcribe() { if (!app.selectedAudio) { toast('请先选择一段录音。'); return; } if (!$('#consent-check').checked) { toast('转写前，请确认你有权使用这段录音。'); return; } const button = $('#transcribe-audio'); const data = new FormData(); data.append('audio', app.selectedAudio); data.append('consent', 'true'); data.append('async', 'true'); busy(button, true, '正在提交转写任务...'); $('#audio-state').textContent = '正在上传，后台转写时间取决于录音长度...'; try { const response = await fetch('/api/transcribe', { method: 'POST', body: data, headers: accessHeaders() }); const result = await response.json(); if (!response.ok || !result.ok) throw Error(result.error || '转写失败'); const output = await waitForTask(result.task, task => { $('#audio-state').textContent = task.status === 'queued' ? `转写任务排队中 · 第 ${task.attempt || 0} 次` : `正在转写音频 · 第 ${task.attempt || 1} 次`; }); const transcription = output.transcription; field('transcript').value = transcription.transcript; updateSensitiveWarning(); $('#audio-state').textContent = `已转写${transcription.language ? ' · ' + transcription.language : ''}${transcription.notes ? ' · ' + transcription.notes : ''}`; setSaveState('有未保存修改'); } catch (error) { $('#audio-state').textContent = '转写失败'; toast(error.message); } finally { busy(button, false, ''); } }
async function reviewInterview() { if (!$('#consent-check').checked) { toast('生成复盘前，请确认你有权使用这份面试材料。'); return; } const button = $('#review-button'); busy(button, true, 'Gemini 正在复盘...'); setReviewState('正在分析证据', 'running'); try { const record = await saveInterview(); const accepted = await api(`/api/interviews/${record.id}/review`, { method: 'POST', body: JSON.stringify({ redact_company: $('#redact-company').checked, async: true }) }); const result = await waitForTask(accepted.task, task => setReviewState(task.status === 'queued' ? '排队中' : '正在分析证据', 'running')); app.current = result.interview; fillInterview(app.current); renderReview(app.current.review); setReviewState('已生成', 'ready'); await refreshInterviews(); } catch (error) { setReviewState('生成失败'); toast(error.message); } finally { busy(button, false, ''); } }

const NOTE_TYPE_CLASS = { '命中': 'hit', '补刀': 'gap', '通用': 'common' };
async function ensureJdResearchForQuestions() { const raw = field('job_description').value.trim(); if (raw.length < 30) return; if (!app.jdAnalysis) { await extractJd(); return; } if (!app.researchCandidates.length) await autoSearchFromJd(raw, app.jdAnalysis); }
async function generateNoteQuestions() { const button = $('#note-questions'); busy(button, true, '正在出题...'); try { await ensureJdResearchForQuestions(); const payload = { company: field('company').value, role: field('role').value, job_description: field('job_description').value, resume_context: field('resume_context').value, jd_analysis: app.jdAnalysis, research_context: app.researchCandidates, interview_id: app.selectedId || '' }; const data = await api('/api/note-questions', { method: 'POST', body: JSON.stringify(payload) }); app.noteQuestions = data.questions || []; renderNoteQuestions(app.noteQuestions, data.research_meta); } catch (error) { toast(error.message); } finally { busy(button, false, ''); } }
function renderNoteQuestions(questions, researchMeta = null) { const panel = $('#note-questions-panel'); panel.replaceChildren(); panel.hidden = !questions.length; if (!questions.length) return; const meta = document.createElement('p'); meta.className = 'note-research-meta'; const count = Number(researchMeta?.provided_count || 0); const approved = Number(researchMeta?.approved_count || 0); meta.textContent = count ? `研究上下文：已参考 ${count} 条公开线索，其中 ${approved} 条人工确认可引用。${researchMeta?.note || '公开线索只影响追问方向，不进入本场表现证据。'}` : (researchMeta?.note || '未获取到公开研究线索，本次问题仅基于 JD 与简历。'); panel.append(meta); questions.forEach(q => { const card = document.createElement('article'); card.className = 'note-question'; card.dataset.id = q.id; card.innerHTML = '<div class="note-question-head"><span class="note-badge"></span><strong></strong></div><p class="note-why"></p><textarea rows="2" placeholder="趁记忆新鲜，简短记下..."></textarea>'; const badge = card.querySelector('.note-badge'); badge.textContent = q.type || '问题'; badge.classList.add(NOTE_TYPE_CLASS[q.type] || 'common'); card.querySelector('strong').textContent = q.question; const basis = q.research_basis?.length ? ` · 公开线索：${q.research_basis.join('、')}` : ''; card.querySelector('.note-why').textContent = q.why_asked ? `为什么问：${q.why_asked}${basis}` : basis; panel.append(card); }); const actions = document.createElement('div'); actions.className = 'note-questions-actions'; const merge = document.createElement('button'); merge.type = 'button'; merge.className = 'secondary-button compact-button'; merge.textContent = '把问答整理进转写'; merge.onclick = collectNoteAnswersIntoTranscript; actions.append(merge); panel.append(actions); }
function collectNoteAnswersIntoTranscript() { const blocks = []; $$('#note-questions-panel .note-question').forEach(card => { const answer = card.querySelector('textarea').value.trim(); if (!answer) return; const question = card.querySelector('strong').textContent; blocks.push(`Q: ${question}\nA: ${answer}`); }); if (!blocks.length) { toast('先填写至少一个回答，再并入转写。'); return; } const transcript = field('transcript'); const addition = `【面后速记】\n${blocks.join('\n\n')}`; transcript.value = transcript.value.trim() ? `${transcript.value.trim()}\n\n${addition}` : addition; updateSensitiveWarning(); setSaveState('有未保存修改'); toast('已并入转写，可继续补充或生成复盘。'); }


function renderResumeList() { const list = $('#resume-list'); list.replaceChildren(); if (!app.resumes.length) { list.innerHTML = '<p class="empty-copy">还没有简历版本。</p>'; return; } app.resumes.forEach(item => { const button = document.createElement('button'); button.type = 'button'; button.className = `interview-item ${item.id === app.editingResumeId ? 'active' : ''}`; button.innerHTML = '<strong></strong><span></span>'; button.querySelector('strong').textContent = item.name; button.querySelector('span').textContent = item.target_role || '未填写目标岗位'; button.onclick = () => loadResume(item.id); list.append(button); }); }
function resetResume() { app.editingResumeId = null; app.selectedResumeFile = null; ['resume-name', 'resume-target', 'resume-content'].forEach(id => $(`#${id}`).value = ''); $('#resume-file').value = ''; $('#resume-file-consent').checked = false; $('#resume-file-state').textContent = '尚未选择文件'; renderResumeList(); }
async function loadResume(id) { try { const resume = (await api(`/api/resumes/${id}`)).resume; app.editingResumeId = id; $('#resume-name').value = resume.name; $('#resume-target').value = resume.target_role; $('#resume-content').value = resume.content; renderResumeList(); setView('resume-view'); } catch (error) { toast(error.message); } }
async function saveResume() { const button = $('#save-resume'); busy(button, true, '正在保存...'); try { const payload = { name: $('#resume-name').value, target_role: $('#resume-target').value, content: $('#resume-content').value }; const data = app.editingResumeId ? await api(`/api/resumes/${app.editingResumeId}`, { method: 'PUT', body: JSON.stringify(payload) }) : await api('/api/resumes', { method: 'POST', body: JSON.stringify(payload) }); app.editingResumeId = data.resume.id; await refreshResumes(); app.resumeId = data.resume.id; $('#resume-select').value = app.resumeId; $('#resume-preview').textContent = `已关联：${data.resume.name}。保存面试时会记录当时的内容快照。`; renderResumeList(); } catch (error) { toast(error.message); } finally { busy(button, false, ''); } }
async function selectResume() { app.resumeId = $('#resume-select').value; if (!app.resumeId) { field('resume_context').value = ''; updateSensitiveWarning(); $('#resume-preview').textContent = '暂未关联简历。'; return; } try { const resume = (await api(`/api/resumes/${app.resumeId}`)).resume; field('resume_context').value = resume.content; updateSensitiveWarning(); $('#resume-preview').textContent = `已关联：${resume.name}。保存面试时会记录当时的内容快照。`; setSaveState('有未保存修改'); } catch (error) { toast(error.message); } }
async function parseResumeFile() { if (!app.selectedResumeFile) { toast('请先选择 PDF 或图片简历。'); return; } if (!$('#resume-file-consent').checked) { toast('解析前，请确认同意将文件发送给 Gemini。'); return; } const button = $('#parse-resume-file'); const data = new FormData(); data.append('resume', app.selectedResumeFile); data.append('consent', 'true'); busy(button, true, 'Gemini 正在解析...'); $('#resume-file-state').textContent = '正在上传并解析简历文件...'; try { const response = await fetch('/api/resumes/parse', { method: 'POST', body: data, headers: accessHeaders() }); const result = await response.json(); if (!response.ok || !result.ok) throw Error(result.error || '简历解析失败'); $('#resume-name').value = result.resume.name; $('#resume-target').value = result.resume.target_role; $('#resume-content').value = result.resume.content; $('#resume-file-state').textContent = '解析完成，请检查并保存为新版本。'; } catch (error) { $('#resume-file-state').textContent = '解析失败'; toast(error.message); } finally { busy(button, false, ''); } }

function researchPayload() { return { title: $('#research-title').value, url: $('#research-url').value, platform: $('#research-platform').value, company: $('#research-company').value, role: $('#research-role').value, round_name: $('#research-round').value, published_date: $('#research-date').value, tags: $('#research-tags').value, source_text: $('#research-source').value, comments_text: $('#research-comments').value, notes: $('#research-notes').value, ...(app.pendingResearchMeta || {}) }; }
function setResearchState(text, kind = '') { $('#research-state').textContent = text; $('#research-state').className = `save-state ${kind}`; }
function resetResearch() { app.editingResearchId = null; app.pendingResearchMeta = null; ['research-title', 'research-url', 'research-company', 'research-round', 'research-date', 'research-tags', 'research-source', 'research-comments', 'research-notes'].forEach(id => $(`#${id}`).value = ''); $('#research-platform').value = '牛客'; $('#research-role').value = '产品经理'; setResearchState('新资料'); renderResearchList(); }
function fillResearch(record) { app.editingResearchId = record.id; app.pendingResearchMeta = { platform_id: record.platform_id || '', search_query: record.search_query || '', source_kind: record.source_kind || '', provenance_status: record.provenance_status || '', retrieved_at: record.retrieved_at || '' }; $('#research-title').value = record.title || ''; $('#research-url').value = record.url || ''; $('#research-platform').value = record.platform || '其他'; $('#research-company').value = record.company || ''; $('#research-role').value = record.role || ''; $('#research-round').value = record.round_name || ''; $('#research-date').value = record.published_date || ''; $('#research-tags').value = record.tags || ''; $('#research-source').value = record.source_text || ''; $('#research-comments').value = record.comments_text || ''; $('#research-notes').value = record.notes || ''; setResearchState(record.status === 'candidate' ? '待摘录原文' : '已入库', record.status === 'candidate' ? '' : 'saved'); }
function statusLabel(status) { return ({ candidate: '候选 · 待预审', auto_approved: 'AI 预审 · 待确认', needs_review: '待人工确认', approved: '人工确认 · 可引用', dismissed: '不使用' })[status] || '未知'; }
function renderResearchList() { const list = $('#research-list'); list.replaceChildren(); if (!app.research.length) { list.innerHTML = '<p class="empty-copy">还没有公开资料。先搜索，再由 AI 生成出题线索并确认原帖。</p>'; return; } app.research.forEach(record => { const card = document.createElement('article'); card.className = 'research-item'; const assessment = record.assessment || {}; const screening = record.screening || {}; const breakdown = Object.entries(screening.relevance_breakdown || {}).map(([key, value]) => `${key} ${value}`).join(' · '); const leadText = (assessment.question_leads || []).filter(item => item && item.question).slice(0, 2).map(item => item.question).join('；'); card.innerHTML = '<div class="research-top"><div><a target="_blank" rel="noreferrer"></a><p></p></div><div class="badge-row"><span class="status-badge"></span><span class="confidence"></span></div></div><p class="research-summary"></p><p class="research-screening"></p><div class="research-meta"></div><div class="research-actions"></div>'; const link = card.querySelector('a'); link.href = record.url; link.textContent = record.title; card.querySelector('.research-top p').textContent = [record.platform, record.company, record.role, record.round_name, record.published_date].filter(Boolean).join(' · '); const badge = card.querySelector('.status-badge'); badge.textContent = statusLabel(record.status); badge.classList.add(record.status); card.querySelector('.confidence').textContent = record.assessment ? `AI 置信度 ${record.confidence}%` : '尚未预审'; card.querySelector('.research-summary').textContent = assessment.summary || (record.source_text || '').slice(0, 240) || '未填写摘要'; card.querySelector('.research-screening').textContent = screening.relevance != null ? `相关度提示 ${screening.relevance}/100${breakdown ? ` · ${breakdown}` : ''}` : '相关度尚未计算'; card.querySelector('.research-meta').textContent = assessment.concerns?.length ? `限制：${assessment.concerns.join('；')}${leadText ? ` · 出题线索：${leadText}` : ''}` : `资料仅作为公开经验参考，复盘中会保留原链接与日期。${leadText ? ` 出题线索：${leadText}` : ''}`; const actions = card.querySelector('.research-actions'); const edit = document.createElement('button'); edit.className = 'secondary-button compact-button'; edit.textContent = '查看/编辑'; edit.onclick = () => { fillResearch(record); setView('research-view'); window.scrollTo({ top: 0, behavior: 'smooth' }); }; actions.append(edit); if (['needs_review', 'auto_approved'].includes(record.status)) { const approve = document.createElement('button'); approve.className = 'secondary-button compact-button'; approve.textContent = '确认可引用'; approve.onclick = () => updateResearchStatus(record.id, 'approved'); actions.append(approve); } if (record.status !== 'dismissed') { const dismiss = document.createElement('button'); dismiss.className = 'text-button'; dismiss.textContent = '不使用'; dismiss.onclick = () => updateResearchStatus(record.id, 'dismissed'); actions.append(dismiss); } list.append(card); }); }
async function saveAndAssessResearch() { const button = $('#research-assess'); busy(button, true, '正在入库...'); try { const payload = researchPayload(); const stored = app.editingResearchId ? await api(`/api/research/${app.editingResearchId}`, { method: 'PUT', body: JSON.stringify(payload) }) : await api('/api/research', { method: 'POST', body: JSON.stringify(payload) }); app.editingResearchId = stored.research.id; setResearchState('AI 正在预审...'); const assessed = await api(`/api/research/${stored.research.id}/assess`, { method: 'POST', body: '{}' }); fillResearch(assessed.research); await refreshResearch(); toast(`资料已预审：${statusLabel(assessed.research.status)}`); } catch (error) { setResearchState('预审失败'); toast(error.message); } finally { busy(button, false, ''); } }
async function updateResearchStatus(id, status) { try { await api(`/api/research/${id}/status`, { method: 'POST', body: JSON.stringify({ status }) }); await refreshResearch(); } catch (error) { toast(error.message); } }
function renderSearchMeta(meta) {
  const root = $('#search-meta');
  root.replaceChildren();
  root.hidden = !meta;
  if (!meta) return;
  const title = document.createElement('strong'); title.textContent = `${meta.platform_label || '全网'} · 已尝试 ${meta.queries_tried?.length || 0} 条查询 · 候选 ${meta.result_count || 0}`; root.append(title);
  (meta.queries_tried || []).slice(0, 3).forEach(query => { const item = document.createElement('span'); item.textContent = query; root.append(item); });
  const statuses = Object.entries(meta.fetch_status_counts || {}).map(([status, count]) => `${status} ${count}`).join(' · ');
  if (statuses) { const item = document.createElement('span'); item.textContent = `公开页读取：${statuses}`; root.append(item); }
  if (meta.failure_reasons?.length) { const item = document.createElement('p'); item.textContent = `失败说明：${meta.failure_reasons.join('；')}`; root.append(item); }
  if (meta.mode === 'public_discovery_with_bounded_fetch') { const item = document.createElement('p'); item.textContent = '已尝试读取白名单公开页；自动读取不等于人工确认，脚本壳或正文不足的资料仍需核对原帖。'; root.append(item); }
  if (meta.cache_hit) { const item = document.createElement('p'); item.textContent = `已命中本地研究缓存（${Math.round((meta.cache_ttl_seconds || 0) / 60)} 分钟内），未重复调用联网搜索；缓存不会改变来源可信度。`; root.append(item); }
  if (meta.empty_reason) { const reason = document.createElement('p'); reason.textContent = `${meta.empty_reason} 可以换同义词，或手动粘贴小红书原帖链接。`; root.append(reason); }
}

function renderDiscovery(candidates) {
  const root = $('#discovery-results'); root.replaceChildren();
  if (!candidates?.length) { root.innerHTML = '<p class="empty-copy">没有发现通过来源校验的候选资料。结果稀疏时请换主题、轮次或手动粘贴原帖。</p>'; return; }
  candidates.forEach(candidate => {
    const card = document.createElement('article'); card.className = 'discovery-item'; card.innerHTML = '<a target="_blank" rel="noreferrer"></a><p></p><div><span></span><button class="secondary-button compact-button" type="button">带入资料库</button></div>';
    const screening = candidate.screening || {};
    card.querySelector('a').href = candidate.url; card.querySelector('a').textContent = candidate.title;
    card.querySelector('p').textContent = `${candidate.summary || '候选公开资料'}${screening.reason ? ` · 初筛：${screening.reason}` : ''}`;
    const breakdown = screening.relevance_breakdown ? Object.entries(screening.relevance_breakdown).map(([key, value]) => `${key} ${value}`).join(' / ') : '';
    const fetchLabel = candidate.fetch_status === 'fetched_metadata' ? '已自动读取公开页' : candidate.fetch_status === 'shell_only' ? '页面仅返回脚本壳' : candidate.fetch_status === 'blocked' ? '页面拒绝读取' : '需人工确认';
    card.querySelector('span').textContent = [candidate.platform, candidate.published_date, candidate.platform_id ? `来源 ${candidate.platform_id}` : '', screening.relevance != null ? `相关度提示 ${screening.relevance}/100` : '', breakdown, fetchLabel].filter(Boolean).join(' · ') || '公开搜索结果';
  card.querySelector('button').onclick = () => importResearchCandidate(candidate);
    root.append(card);
  });
}
async function importResearchCandidate(candidate) { try { const data = await api('/api/research/candidate', { method: 'POST', body: JSON.stringify({ candidate }) }); const research = data.research || {}; const excerptReady = (research.source_text || '').trim().length >= 80; fillResearch(research); await refreshResearch(); setView('research-view'); $('#research-source').focus(); if (data.existing) { toast('候选已存在，已自动回填。'); } else if (excerptReady) { toast('候选已自动收录，标题、链接、正文和查询元数据已回填；请检查原帖后进行 AI 预审。'); } else { toast('候选已自动收录，标题、链接和平台已回填；公开页正文不足，请补充原帖摘录。'); } } catch (error) { toast(error.message); } }

 async function discoverResearch(event) { event.preventDefault(); const button = $('#discover-button'); busy(button, true, 'Gemini 正在搜索...'); try { const payload = { company: $('#discover-company').value, role: $('#discover-role').value, round_name: $('#discover-round').value, topic: $('#discover-topic').value, platform: $('#discover-platform').value, job_description: field('job_description').value, jd_analysis: app.jdAnalysis }; const data = await api('/api/research/discover', { method: 'POST', body: JSON.stringify(payload) }); app.researchCandidates = data.candidates || []; renderSearchMeta(data.search_meta); renderDiscovery(data.candidates); } catch (error) { toast(error.message); } finally { busy(button, false, ''); } }
 async function runResearchAgent() { const button = $('#agent-button'); busy(button, true, 'Agent 正在自主调研...'); try { const payload = { company: $('#discover-company').value, role: $('#discover-role').value, round_name: $('#discover-round').value, topic: $('#discover-topic').value, platform: $('#discover-platform').value, job_description: field('job_description').value, jd_analysis: app.jdAnalysis, async: true }; const accepted = await api('/api/research/agent', { method: 'POST', body: JSON.stringify(payload) }); const data = await waitForTask(accepted.task, task => { if (task.status === 'queued') renderSearchMeta({ platform_label: '后台排队中', result_count: 0 }); if (task.status === 'running') renderSearchMeta({ platform_label: 'Agent 调研中', result_count: 0 }); }); app.researchCandidates = data.persisted || data.collected || []; renderSearchMeta(data.search_meta); renderAgentTrace(data.trace, data.stop_reason, data.found_enough); renderDiscovery(app.researchCandidates); await refreshResearch(); if (data.skipped?.length) toast(`已收录 ${app.researchCandidates.length} 条，跳过 ${data.skipped.length} 条不合规候选。`); } catch (error) { toast(error.message); } finally { busy(button, false, ''); } }
function renderAgentTrace(trace, stopReason, foundEnough) { const root = $('#agent-trace'); root.replaceChildren(); root.hidden = !(trace && trace.length); if (!trace || !trace.length) return; trace.forEach(step => { const card = document.createElement('div'); card.className = 'agent-round'; card.innerHTML = '<strong></strong><p></p><p class="agent-query"></p>'; const label = step.action === 'stop' ? '停止' : step.action === 'fetch' ? '读取公开页' : step.action === 'cache' ? '命中缓存' : '搜索'; card.querySelector('strong').textContent = `第 ${step.round} 轮 · ${label}${step.action === 'search' ? ` · 新增 ${step.added || 0}` : ''}${step.action === 'fetch' ? ` · 读取 ${step.fetched || 0}` : ''}${step.action === 'cache' ? ` · 候选 ${step.added || 0}` : ''}`; card.querySelector('p').textContent = step.reasoning || ''; const q = card.querySelector('.agent-query'); if (step.query) q.textContent = `${step.action === 'fetch' ? '动作' : '查询词'}：${step.query}`; else q.remove(); root.append(card); }); const stop = document.createElement('p'); stop.className = 'agent-stop'; stop.textContent = `${foundEnough ? '已找够待确认资料' : '未达目标数量'} · ${stopReason || '结束'}`; root.append(stop); }

const TREND_LABELS = { improving: '↑ 改进中', declining: '↓ 下滑', stable: '→ 持平', insufficient_data: '样本不足' };
function renderMemory(memory) { const root = $('#memory-summary'); root.replaceChildren(); const items = [{ label: '已复盘面试', value: memory.reviewed_interviews || 0 }, { label: '待完成行动', value: memory.open_actions?.length || 0 }, { label: '重复薄弱点', value: memory.recurring_gaps?.length || 0 }]; items.forEach(item => { const block = document.createElement('div'); block.innerHTML = '<span></span><strong></strong>'; block.querySelector('span').textContent = item.label; block.querySelector('strong').textContent = item.value; root.append(block); }); const patterns = document.createElement('div'); patterns.className = 'memory-patterns'; const generated = document.createElement('span'); generated.textContent = `记忆快照：${memory.generated_at || '刚刚计算'}`; patterns.append(generated); const audit = memory.audit || {}; const auditTag = document.createElement('span'); auditTag.textContent = audit.replayable ? `可回放聚合：${audit.input_count || 0} 场 · ${audit.algorithm_version || 'deterministic'}` : '聚合来源未提供'; patterns.append(auditTag); const comparability = document.createElement('span'); comparability.className = memory.comparability === 'comparable' ? 'memory-ok' : 'memory-warning'; comparability.textContent = memory.comparability === 'comparable' ? '同一评分版本可比较' : `评分可比性：${memory.comparability || '未知'}`; patterns.append(comparability); if (memory.stage === 'cold_start') { const n = memory.interviews_to_unlock_trend || 0; patterns.innerHTML += '<p>跨场成长趋势</p>'; const hint = document.createElement('span'); hint.className = 'cold-start-hint'; hint.textContent = n > 0 ? `再完成 ${n} 场复盘即可解锁跨场成长趋势` : '再完成 1 场复盘即可解锁跨场成长趋势'; patterns.append(hint); } else { const label = document.createElement('p'); label.textContent = '当前重复出现'; patterns.append(label); (memory.recurring_gaps || []).slice(0, 4).forEach(item => { const tag = document.createElement('span'); tag.textContent = `${item.title} · ${item.occurrences}次 · ${item.sources?.length || item.occurrences}场有记录`; patterns.append(tag); }); if (!(memory.recurring_gaps || []).length) patterns.append('暂无足够数据'); const trends = (memory.skill_summary || []).filter(s => s.trend && s.trend !== 'insufficient_data'); if (trends.length) { const trendBox = document.createElement('div'); trendBox.className = 'memory-trends'; trendBox.innerHTML = '<p>能力趋势</p>'; trends.slice(0, 6).forEach(s => { const tag = document.createElement('span'); tag.className = `trend-${s.trend}`; tag.textContent = `${s.skill_id} · ${TREND_LABELS[s.trend] || s.trend}${s.trend_comparable === false ? ' · 谨慎比较' : ''}`; trendBox.append(tag); }); patterns.append(trendBox); } } const outcome = memory.outcome_signal || {}; const outcomeTag = document.createElement('span'); outcomeTag.textContent = '结果反馈：' + (outcome.sample_count || 0) + ' 场 · 通过 ' + (outcome.passed?.count || 0) + ' / 未通过 ' + (outcome.failed?.count || 0) + ' · ' + (outcome.status || '样本不足'); patterns.append(outcomeTag); const outcomeNote = document.createElement('span'); outcomeNote.textContent = outcome.interpretation || '结果为自报训练反馈，不是招聘预测。'; patterns.append(outcomeNote); root.append(patterns); }
function saveMemoryOverride(gapKey, title, ignored) { return api(`/api/memory/gaps/${encodeURIComponent(gapKey)}`, { method: 'PUT', body: JSON.stringify({ title, ignored }) }).then(() => refreshGrowthMemory()); }
function resetMemoryOverride(gapKey) { return api(`/api/memory/gaps/${encodeURIComponent(gapKey)}`, { method: 'DELETE' }).then(() => refreshGrowthMemory()); }
function appendMemoryGovernance(memory) { const root = $('#memory-summary'); if (!(memory.recurring_gaps || []).length) return; const section = document.createElement('section'); section.className = 'memory-governance'; const heading = document.createElement('p'); heading.textContent = '记忆来源与标签治理'; section.append(heading); const overrides = Object.fromEntries((memory.gap_overrides || []).map(item => [item.gap_key, item])); (memory.recurring_gaps || []).slice(0, 8).forEach(item => { const details = document.createElement('details'); const summary = document.createElement('summary'); summary.textContent = `${item.title} · ${item.occurrences} 次`; details.append(summary); const sources = document.createElement('div'); sources.className = 'memory-sources'; (item.sources || []).forEach(source => { const line = document.createElement('p'); line.textContent = `${source.company || '未命名公司'} · ${source.role || '岗位'} · ${source.round_name || '面试'} · ${source.date || '未填日期'}${source.evidence ? ` · 证据：${source.evidence}` : ''}`; sources.append(line); }); const controls = document.createElement('div'); controls.className = 'memory-controls'; const input = document.createElement('input'); input.value = overrides[item.gap_key]?.title || item.title; input.maxLength = 160; input.placeholder = '修改缺口名称'; const rename = document.createElement('button'); rename.type = 'button'; rename.className = 'secondary-button compact-button'; rename.textContent = '保存名称'; rename.onclick = () => saveMemoryOverride(item.gap_key, input.value.trim(), false).catch(error => toast(error.message)); const ignore = document.createElement('button'); ignore.type = 'button'; ignore.className = 'text-button'; ignore.textContent = '忽略此缺口'; ignore.onclick = () => { if (window.confirm('忽略后，长期记忆会从聚合结果中移除它。继续吗？')) saveMemoryOverride(item.gap_key, input.value.trim(), true).catch(error => toast(error.message)); }; controls.append(input, rename, ignore); if (overrides[item.gap_key]) { const reset = document.createElement('button'); reset.type = 'button'; reset.className = 'text-button'; reset.textContent = '恢复默认'; reset.onclick = () => resetMemoryOverride(item.gap_key).catch(error => toast(error.message)); controls.append(reset); } details.append(sources, controls); section.append(details); }); root.append(section); }
const renderMemoryWithGovernance = renderMemory;
function appendMemoryAudit(memory) { const events = memory.override_events || []; if (!events.length) return; const root = $('#memory-summary'); const section = document.createElement('section'); section.className = 'memory-governance'; const heading = document.createElement('p'); heading.textContent = '最近治理记录'; section.append(heading); const labels = { upsert: '修改标签', delete: '删除标签', revert: '撤销操作' }; events.slice(0, 8).forEach(event => { const row = document.createElement('div'); row.className = 'memory-audit-row'; const line = document.createElement('p'); line.textContent = `${labels[event.action] || event.action} · ${event.title || event.gap_key || '未命名缺口'} · ${event.created_at || '时间未知'}`; const button = document.createElement('button'); button.type = 'button'; button.className = 'text-button'; button.textContent = '撤销'; button.title = '撤销这次治理操作'; button.disabled = event.action === 'revert'; button.onclick = () => { if (!window.confirm('撤销后会恢复这次治理操作之前的标签状态。继续吗？')) return; api(`/api/memory/overrides/audit/${encodeURIComponent(event.id)}/revert`, { method: 'POST', body: JSON.stringify({ confirm: true }) }).then(() => refreshGrowthMemory()).catch(error => toast(error.message)); }; row.append(line, button); section.append(row); }); root.append(section); }
renderMemory = memory => { renderMemoryWithGovernance(memory); appendMemoryGovernance(memory); appendMemoryAudit(memory); };
function renderSkillList(skills) { const root = $('#skill-list'); root.replaceChildren(); skills.forEach(skill => { const item = document.createElement('div'); item.className = 'skill-definition'; item.innerHTML = '<strong></strong><span></span>'; item.querySelector('strong').textContent = skill.name; const anchors = skill.score_anchors || {}; item.querySelector('span').textContent = `${skill.focus} 评分锚点：1 ${anchors['1'] || '未展示'}；3 ${anchors['3'] || '合格'}；5 ${anchors['5'] || '优秀'}`; root.append(item); }); }
function renderGrowthReport(report) { const root = $('#growth-content'); root.replaceChildren(); root.hidden = !report; $('#growth-empty').hidden = !!report; if (!report) return; const summary = document.createElement('div'); summary.className = 'review-summary'; summary.textContent = report.summary; root.append(summary); const assessment = reviewSection('阶段判断'); const assessmentText = document.createElement('p'); assessmentText.className = 'body-copy'; assessmentText.textContent = report.stage_assessment; assessment.append(assessmentText); root.append(assessment); renderCoachItems(root, '可观察到的变化', report.growth_signals, 'interpretation'); if (report.recurring_patterns?.length) { const section = reviewSection('持续模式'); const list = document.createElement('div'); list.className = 'pattern-list'; report.recurring_patterns.forEach(pattern => { const row = document.createElement('article'); row.innerHTML = '<strong></strong><span></span><p></p><p class="next"></p>'; row.querySelector('strong').textContent = pattern.skill; row.querySelector('span').textContent = `${pattern.occurrences} 次`; row.querySelector('p').textContent = `证据：${pattern.evidence}`; row.querySelector('.next').textContent = pattern.recommendation; list.append(row); }); section.append(list); root.append(section); } if (report.priority_training?.length) { const section = reviewSection('最高优先级训练'); const list = document.createElement('div'); list.className = 'training-list'; report.priority_training.forEach(item => { const row = document.createElement('article'); row.innerHTML = '<strong></strong><p></p><p class="next"></p>'; row.querySelector('strong').textContent = item.action; row.querySelector('p').textContent = `${item.why_now}${item.source ? ` · 来源：${item.source}` : ''}`; row.querySelector('.next').textContent = `验收标准：${item.success_criterion}`; list.append(row); }); section.append(list); root.append(section); } if (report.report_grounding) { const section = reviewSection('报告来源'); const sourceText = document.createElement('p'); sourceText.className = 'body-copy'; sourceText.textContent = report.report_grounding.note || '结构化报告字段由确定性长期记忆提供。'; section.append(sourceText); root.append(section); } const quality = reviewSection('数据边界'); const qualityText = document.createElement('p'); qualityText.className = 'body-copy'; qualityText.textContent = report.data_quality; quality.append(qualityText); root.append(quality); }
async function refreshGrowthMemory() { try { const data = await api('/api/growth-memory'); data.memory.override_events = data.override_events || []; renderMemory(data.memory); $('#growth-state').textContent = data.memory.reviewed_interviews ? '已有记录' : '等待数据'; } catch (error) { toast(error.message); } }
async function generateGrowth() { const button = $('#generate-growth'); busy(button, true, 'Gemini 正在汇总...'); $('#growth-state').textContent = '正在分析'; try { const snapshot = await api('/api/growth-memory'); snapshot.memory.override_events = snapshot.override_events || []; renderMemory(snapshot.memory); if (snapshot.memory.stage === 'cold_start') { const n = snapshot.memory.interviews_to_unlock_trend || 1; $('#growth-state').textContent = '样本不足'; toast(`样本不足：再完成 ${n} 场复盘即可生成跨场成长报告。`); return; } const data = await api('/api/growth-report', { method: 'POST', body: '{}' }); data.memory.override_events = snapshot.override_events; renderMemory(data.memory); renderGrowthReport(data.report); $('#growth-state').textContent = '已生成'; } catch (error) { $('#growth-state').textContent = '生成失败'; toast(error.message); } finally { busy(button, false, ''); } }
async function refreshBackups() { try { const data = await api('/api/backups'); const select = $('#backup-select'); const current = select.value; select.replaceChildren(new Option('选择本地备份', '')); (data.backups || []).forEach(item => { const integrity = item.integrity_status === 'verified' ? '完整性已验证' : item.integrity_status === 'legacy_unverified' ? '旧备份未验证' : '备份需检查'; select.add(new Option(`${item.created_at} · ${item.counts.interviews} 场面试 · ${integrity}`, item.backup_id)); }); select.value = current; } catch (error) { toast(error.message); } }
async function exportData() { try { const data = await api('/api/export'); const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' }); const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = `autumn-pm-coach-export-${new Date().toISOString().slice(0, 10)}.json`; link.click(); URL.revokeObjectURL(link.href); $('#data-state').textContent = '已导出'; } catch (error) { toast(error.message); } }
async function createBackup() { try { const data = await api('/api/backup', { method: 'POST', body: '{}' }); $('#data-state').textContent = `备份已创建 · ${data.backup.backup_id}`; await refreshBackups(); toast('本地备份已创建。请将备份目录纳入你自己的安全备份策略。'); } catch (error) { toast(error.message); } }
async function restoreBackup() { const backupId = $('#backup-select').value; if (!backupId) { toast('先选择一个本地备份。'); return; } if (!window.confirm('恢复备份会覆盖当前面试、简历、资料和记忆标签。确定继续吗？')) return; try { await api(`/api/backup/restore/${encodeURIComponent(backupId)}`, { method: 'POST', body: JSON.stringify({ confirm: true }) }); $('#data-state').textContent = '已恢复备份'; await refreshInterviews(); await refreshResumes(); await refreshResearch(); await refreshGrowthMemory(); toast('备份已恢复。'); } catch (error) { toast(error.message); } }
async function cleanupData(target, label) { if (!window.confirm(`${label}会清除原始正文，但保留结构化结果。确定继续吗？`)) return; try { const data = await api('/api/data/cleanup', { method: 'POST', body: JSON.stringify({ target, confirm: true }) }); $('#data-state').textContent = `已清理 ${data.cleared.transcripts + data.cleared.research_excerpts} 条`; await refreshInterviews(); await refreshResearch(); await refreshGrowthMemory(); } catch (error) { toast(error.message); } }
async function previewRetention() { try { const data = await api('/api/data/retention'); const policy = data.policy; $('#data-state').textContent = `预计清理 ${policy.total_eligible_records} 条原始正文`; toast(`保留 ${policy.retention_days} 天：转写 ${policy.eligible_records.transcripts} 条，面经正文 ${policy.eligible_records.research_excerpts} 条。`); } catch (error) { toast(error.message); } }
async function applyRetention() { const days = Number($('#retention-days').value); if (!Number.isInteger(days) || days < 1) { toast('请填写大于 0 的保留天数。'); return; } await previewRetention(); if (!window.confirm(`将清除早于 ${days} 天的原始转写和面经正文，并保留结构化结果。建议先备份，确定继续吗？`)) return; try { const data = await api('/api/data/retention', { method: 'POST', body: JSON.stringify({ retention_days: days, target: 'all_transient', confirm: true }) }); const cleared = data.retention.cleared; $('#data-state').textContent = `保留策略已执行 · ${cleared.transcripts + cleared.research_excerpts} 条`; await refreshInterviews(); await refreshResearch(); await refreshGrowthMemory(); } catch (error) { toast(error.message); } }

