$('#review-button').onclick = reviewInterview; $('#extract-jd').onclick = extractJd; $('#transcribe-audio').onclick = transcribe; $('#resume-select').onchange = selectResume; $('#note-questions').onclick = generateNoteQuestions; $('#delete-interview').onclick = deleteInterview;
