$('#new-resume').onclick = resetResume; $('#resume-form').onsubmit = event => { event.preventDefault(); saveResume(); }; $('#resume-file').onchange = event => { app.selectedResumeFile = event.target.files?.[0] || null; $('#resume-file-state').textContent = app.selectedResumeFile ? `${app.selectedResumeFile.name} · ${(app.selectedResumeFile.size / 1024 / 1024).toFixed(1)} MB` : '尚未选择文件'; }; $('#parse-resume-file').onclick = parseResumeFile;
$('#research-new').onclick = resetResearch; $('#research-form').onsubmit = event => { event.preventDefault(); saveAndAssessResearch(); }; $('#discover-form').onsubmit = discoverResearch; $('#agent-button').onclick = runResearchAgent; $('#generate-growth').onclick = generateGrowth; $('#open-jd-research').onclick = () => setView('research-view'); $('#export-data').onclick = exportData; $('#create-backup').onclick = createBackup; $('#restore-backup').onclick = restoreBackup; $('#clear-transcripts').onclick = () => cleanupData('transcripts', '清除历史转写'); $('#clear-research').onclick = () => cleanupData('research_excerpts', '清除面经正文'); $('#retention-preview').onclick = previewRetention; $('#retention-apply').onclick = applyRetention;
