async function initializeApp() { resetInterview(); const recovery = await api('/api/recovery'); if (recovery.recovery?.recovery_required) { $('#model-status').textContent = '需要恢复本地数据'; $('#data-state').textContent = '数据需要恢复'; $('.status-dot').className = 'status-dot error'; toast('本地数据需要恢复：请先检查备份，再继续使用。'); return; } await Promise.all([refreshResumes(), refreshInterviews(), refreshResearch(), refreshGrowthMemory(), refreshBackups(), api('/api/skills').then(data => renderSkillList(data.skills))]); try { const data = await api('/api/health'); const backup = Math.max(0, (data.providers || []).length - 1); const demoTag = data.demo_mode && !data.can_write ? ' · 只读演示' : ''; $('#model-status').textContent = `${data.active_provider || 'gemini'} · ${data.model}${backup ? ` · ${backup} 个备用` : ''}${demoTag}`; $('.status-dot').className = 'status-dot ready'; } catch (error) { $('#model-status').textContent = error.status === 503 && error.message.includes('模型') ? '模型未配置' : '服务需要检查'; $('.status-dot').className = 'status-dot error'; } }
function showLogin(message = '') { $('#login-gate').hidden = false; $('#login-error').hidden = !message; $('#login-error').textContent = message; $('#access-token').focus(); }
$('#login-form').onsubmit = async event => { event.preventDefault(); const button = $('#login-button'); busy(button, true, '正在验证...'); sessionStorage.setItem(ACCESS_TOKEN_KEY, $('#access-token').value); try { await initializeApp(); $('#login-gate').hidden = true; $('#login-error').hidden = true; } catch (error) { sessionStorage.removeItem(ACCESS_TOKEN_KEY); showLogin(error.message); } finally { busy(button, false, ''); } };
(async () => { try { await initializeApp(); } catch (error) { if (error.message === '需要访问口令。') showLogin(); else toast(error.message); } })();
